    if len(s.split()) < 2 and '(' not in s:
        return False
    return True

for ln in lines:
    s = ln.strip()
    if start_pat.match(s):
        in_dis = True
        current = None
        continue
    if in_dis and end_pat.match(s):
        break
    if not in_dis:
        continue
    if is_title(s):
        current = s
        continue
    m = begin_pat.search(s)
    if m and current:
        pairs.append({'Project_Name': current, 'st': m.group(1).strip()})

print('__RESULT__:')
print(json.dumps({'count': len(pairs), 'pairs': pairs[:50]}))
